/**
 * Bin parameters describe the characteristics of the bins, including their size and starting value. Each bin's size can either be specified by a parameter
 * or calculated dynamically. Additionally, bins can be based on either date or numeric values.
 *
 * @see [binParameters](https://developers.arcgis.com/javascript/latest/references/core/rest/support/AttributeBinsQuery/#binParameters)
 */
export type BinParameters = AutoIntervalBinParameters | DateBinParameters | FixedBoundariesBinParameters | FixedIntervalBinParameters;

/**
 * This class configures parameters for the [queryAttributeBins](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/#queryAttributeBins) method, which groups features in a layer or layer view into bins
 * based on numeric or date fields. This operation is useful for summarizing and analyzing large datasets by organizing them into meaningful groups, or bins, making it easier to detect patterns,
 * trends, and anomalies across different ranges or time periods.
 *
 * The [binParameters](https://developers.arcgis.com/javascript/latest/references/core/rest/support/AttributeBinsQuery/#binParameters) property defines bin characteristics like size and start value, while the [outStatistics](https://developers.arcgis.com/javascript/latest/references/core/rest/support/AttributeBinsQuery/#outStatistics) parameter specifies the information each bin provides.
 * Features can be filtered using a [where](https://developers.arcgis.com/javascript/latest/references/core/rest/support/AttributeBinsQuery/#where) condition and a [spatial filter](https://developers.arcgis.com/javascript/latest/references/core/rest/support/AttributeBinsQuery/#geometry). Bins are arranged consecutively with no gaps:
 * they are left-inclusive and right-exclusive, except for the last bin, which is right-inclusive. The method supports multiple statistical aggregations per bin and defaults to
 * a histogram of value frequencies/counts if no specific aggregations are provided in `outStatistics`.
 *
 * Bins are defined using one of the bin parameters, each supporting distinct parameters for handling boundaries between bins. Understanding the purpose of each bin parameter is
 * crucial for understanding binning and boundary settings. There are four types of bin parameters:
 * | Bin parameter type | Description |
 * | ------------------- | ----------- |
 * | [AutoIntervalBinParameters](https://developers.arcgis.com/javascript/latest/references/core/rest/support/AutoIntervalBinParameters/) | You specify the number of [numBins](https://developers.arcgis.com/javascript/latest/references/core/rest/support/AutoIntervalBinParameters/#numBins), [start](https://developers.arcgis.com/javascript/latest/references/core/rest/support/AutoIntervalBinParameters/#start) and [end](https://developers.arcgis.com/javascript/latest/references/core/rest/support/AutoIntervalBinParameters/#end) values of the binning. The bin size is calculated by dividing the dataset's range by this number of bins.|
 * | [FixedBoundariesBinParameters](https://developers.arcgis.com/javascript/latest/references/core/rest/support/FixedBoundariesBinParameters/) | The bins strictly follow the specified [input values](https://developers.arcgis.com/javascript/latest/references/core/rest/support/FixedBoundariesBinParameters/#boundaries). The first item in the array specifies the lower boundary of the first bin, while the last item specifies the upper boundary of the last bin. Intermediate values represent the lower boundaries of each bin. |
 * | [FixedIntervalBinParameters](https://developers.arcgis.com/javascript/latest/references/core/rest/support/FixedIntervalBinParameters/) | The number of bins is not important, but the [interval](https://developers.arcgis.com/javascript/latest/references/core/rest/support/FixedIntervalBinParameters/#interval) size must match the input data. Each bin will cover a range that exactly fits the specified interval. |
 * | [DateBinParameters](https://developers.arcgis.com/javascript/latest/references/core/rest/support/DateBinParameters/) | The [intervals](https://developers.arcgis.com/javascript/latest/references/core/rest/support/DateBinParameters/#interval) are based on calendar units. For example, with monthly intervals, each bin represents an entire month. |
 *
 * @since 4.32
 * @see [FeatureLayer.queryAttributeBins()](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/#queryAttributeBins)
 * @see [Sample - Attribute Bins Query](https://developers.arcgis.com/javascript/latest/sample-code/query-attribute-bins/)
 */
